request.query:
prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?choreo ?choreoName ?witnessType ?witnessName WHERE {
  ?model a bboExt:Model .
  ?model tai:originalId ?orig .
  FILTER(STR(?orig) = "0b21c69687b64d8886fb7cc5dc56ff6c")

  ?defs tai:belongsTo ?model .
  ?choreo tai:belongsTo ?defs .
  OPTIONAL { ?choreo bbo:name ?choreoName . }

  ?start a bboExt:StartEvent ; tai:belongsTo ?choreo .

  # Reach any non-end node from a start
  ?start ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?witness .
  FILTER NOT EXISTS { ?witness a bboExt:EndEvent . }

  # If that witness cannot reach any end, it's evidence of non-termination along some execution path
  FILTER NOT EXISTS {
    ?witness ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?anyEnd .
    ?anyEnd a bboExt:EndEvent .
    ?anyEnd tai:belongsTo ?choreo .
  }

  OPTIONAL { ?witness a ?witnessType . }
  OPTIONAL { ?witness bbo:name ?witnessName . }
}
LIMIT 25
